mapper.select:
SELECT invite_id, party_id, inviter_id, invitee_id, status, created_at, responded_at
FROM party_invite
WHERE invite_id = #{inviteId}

mapper.update:
UPDATE party_invite
SET status = #{status}, responded_at = #{now}
WHERE invite_id = #{inviteId}
    AND inviter_id = #{inviterId}
    AND status = 'PENDING'

